/**
 * @name Taint flow from remote input to OS command execution
 * @description Tracks tainted data from remote sources to Runtime.exec() or ProcessBuilder
 * @kind path-problem
 * @problem.severity error
 * @id java/command-injection-remote
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module CmdInjectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // Runtime.exec() sinks
    exists(MethodCall mc |
      mc.getMethod().hasName("exec") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Runtime") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // ProcessBuilder constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.lang", "ProcessBuilder") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // ProcessBuilder.command()
    exists(MethodCall mc |
      mc.getMethod().hasName("command") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "ProcessBuilder") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module CmdInjectionFlow = TaintTracking::Global<CmdInjectionConfig>;
import CmdInjectionFlow::PathGraph

from CmdInjectionFlow::PathNode source, CmdInjectionFlow::PathNode sink
where CmdInjectionFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "OS command injection from $@.", source.getNode(), "user input"

/**
 * @name Taint flow from DockerRegistryEndpoint URL/imageName to command execution
 * @description Track taint from user-controlled DockerRegistryEndpoint fields to cmds/exec
 * @kind path-problem
 * @problem.severity error
 * @id java/docker-registry-endpoint-to-exec
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking

module DockerCmdConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Source: getUrl(), getEffectiveUrl(), imageName() return values from DockerRegistryEndpoint
    exists(MethodCall mc |
      mc.getMethod().getDeclaringType().hasQualifiedName("org.jenkinsci.plugins.docker.commons.credentials", "DockerRegistryEndpoint") and
      (mc.getMethod().hasName("getUrl") or 
       mc.getMethod().hasName("getEffectiveUrl") or
       mc.getMethod().hasName("imageName") or
       mc.getMethod().hasName("toString")) and
      source.asExpr() = mc
    )
    or
    // Constructor parameters of DockerRegistryEndpoint
    exists(Constructor c, Parameter p |
      c.getDeclaringType().hasQualifiedName("org.jenkinsci.plugins.docker.commons.credentials", "DockerRegistryEndpoint") and
      p = c.getAParameter() and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // cmds() or cmdAsList() calls
    exists(MethodCall mc |
      (mc.getMethod().hasName("cmds") or mc.getMethod().hasName("cmdAsList") or
       mc.getMethod().hasName("launch") or mc.getMethod().hasName("join")) and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // List.add() that feeds into cmds
    exists(MethodCall mc |
      mc.getMethod().hasName("add") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module DockerCmdFlow = TaintTracking::Global<DockerCmdConfig>;
import DockerCmdFlow::PathGraph

from DockerCmdFlow::PathNode source, DockerCmdFlow::PathNode sink
where DockerCmdFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Docker endpoint value flows to command at $@.", source.getNode(), "source"

/**
 * @name Taint from DockerRegistryEndpoint constructor params to ProcStarter cmds
 * @description Track user-supplied URL/username/password from DockerRegistryEndpoint to docker login command
 * @kind path-problem
 * @problem.severity error
 * @id java/docker-login-credential-injection
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking

module DockerLoginConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // RegistryKeyMaterialFactory fields: username, password, endpoint
    exists(Field f |
      f.getDeclaringType().hasQualifiedName("org.jenkinsci.plugins.docker.commons.impl", "RegistryKeyMaterialFactory") and
      (f.hasName("username") or f.hasName("password") or f.hasName("endpoint")) and
      source.asExpr().(FieldAccess).getField() = f
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // ProcStarter method calls: cmds, cmdAsList, stdin, envs
    exists(MethodCall mc |
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("hudson", "Launcher$ProcStarter") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // List.add() for command building
    exists(MethodCall addCall, MethodCall cmdsCall |
      addCall.getMethod().hasName("add") and
      cmdsCall.getMethod().hasName("cmds") and
      addCall.getEnclosingCallable() = cmdsCall.getEnclosingCallable() and
      sink.asExpr() = addCall.getAnArgument()
    )
  }
}

module DockerLoginFlow = TaintTracking::Global<DockerLoginConfig>;
import DockerLoginFlow::PathGraph

from DockerLoginFlow::PathNode source, DockerLoginFlow::PathNode sink
where DockerLoginFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Credential/endpoint value flows to Docker command at $@.", source.getNode(), "source value"

/**
 * @name Username and password flow into docker login command arguments
 * @description Track username and password from RegistryKeyMaterialFactory into ProcStarter command args
 * @kind path-problem
 * @problem.severity error
 * @id java/docker-login-username-password-injection
 * @tags security
 *       external/cwe/cwe-078
 *       external/cwe/cwe-088
 */

import java
import semmle.code.java.dataflow.TaintTracking

module DockerLoginCredConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // username, password, endpoint fields accessed in RegistryKeyMaterialFactory
    exists(FieldAccess fa |
      fa.getField().getDeclaringType().hasQualifiedName("org.jenkinsci.plugins.docker.commons.impl", "RegistryKeyMaterialFactory") and
      (fa.getField().hasName("username") or 
       fa.getField().hasName("password") or
       fa.getField().hasName("endpoint")) and
      source.asExpr() = fa
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // ProcStarter.cmds() call argument 
    exists(MethodCall mc |
      mc.getMethod().hasName("cmds") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // Any add() to a list that gets passed to cmds()
    exists(MethodCall addMc |
      addMc.getMethod().hasName("add") and
      addMc.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.jenkinsci.plugins.docker.commons.impl", "RegistryKeyMaterialFactory") and
      sink.asExpr() = addMc.getArgument(0)
    )
  }
}

module DockerLoginCredFlow = TaintTracking::Global<DockerLoginCredConfig>;
import DockerLoginCredFlow::PathGraph

from DockerLoginCredFlow::PathNode source, DockerLoginCredFlow::PathNode sink
where DockerLoginCredFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Username/password/endpoint flows to docker command argument at $@.", source.getNode(), "credential source"

/**
 * @name Confirmed: username and password flow to docker login ProcStarter without sanitization
 * @description Confirm exact taint path from username/password fields to the docker login command join() call
 * @kind path-problem
 * @problem.severity error
 * @id java/docker-login-argument-injection-confirmed
 * @tags security
 *       external/cwe/cwe-078
 *       external/cwe/cwe-088
 */

import java
import semmle.code.java.dataflow.TaintTracking

module ConfirmedDockerLoginConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // username and password fields specifically (not endpoint which is a URL type)
    exists(FieldAccess fa |
      fa.getField().getDeclaringType().hasQualifiedName("org.jenkinsci.plugins.docker.commons.impl", "RegistryKeyMaterialFactory") and
      (fa.getField().hasName("username") or fa.getField().hasName("password")) and
      source.asExpr() = fa
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // The join() call at line 101 on ProcStarter - which executes the docker login command
    exists(MethodCall joinCall |
      joinCall.getMethod().hasName("join") and
      joinCall.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.jenkinsci.plugins.docker.commons.impl", "RegistryKeyMaterialFactory") and
      // Sink is any argument to add() which feeds the list used in cmds() before join()
      exists(MethodCall addCall |
        addCall.getMethod().hasName("add") and
        addCall.getEnclosingCallable() = joinCall.getEnclosingCallable() and
        sink.asExpr() = addCall.getArgument(0)
      )
    )
  }
}

module ConfirmedDockerLoginFlow = TaintTracking::Global<ConfirmedDockerLoginConfig>;
import ConfirmedDockerLoginFlow::PathGraph

from ConfirmedDockerLoginFlow::PathNode source, ConfirmedDockerLoginFlow::PathNode sink
where ConfirmedDockerLoginFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Argument injection: $@ flows to docker login command argument without sanitization.", source.getNode(), "credential value"
